410→
411→    const normalizedPayload = normalizedType === 'doodle'
412→        ? validateDoodlePayload(payload)
413→        : validateStickyPayload(payload);
414→
415→    const {data: insertedItem, error: insertError} = await supabase
416→    .from('canvas_margin_items')
417→    .insert({
418→        journal_id: journalId,
419→        user_id: userId,
420→        item_type: normalizedType,
421→        payload: normalizedPayload
422→    })
423→    .select(MARGIN_SELECT)
424→    .single();
425→
426→    if(insertError){
427→        console.error('supabase error while adding canvas margin item:', insertError.message);
428→        throw {status: 500, error: 'failed to add canvas margin item'};
429→    }
430→
431→    return normalizeMarginPayload(insertedItem);
432→}
