  82→const useLoadedImage = (src) => {
  83→    const [image, setImage] = useState(null);
  84→
  85→    useEffect(() => {
  86→        if(!src){
  87→            setImage(null);
  88→            return;
  89→        }
  90→
  91→        const img = new window.Image();
  92→        img.crossOrigin = "anonymous";
  93→        img.onload = () => setImage(img);
  94→        img.onerror = () => setImage(null);
  95→        img.src = src;
  96→
  97→        return () => {
