 148→    const stampSize = Math.max(20, Math.round(STAMP_SIZE * stampScale));
 149→    const stampFontSize = Math.max(18, Math.round(STAMP_FONT_SIZE * stampScale));
 150→    const profileSize = Math.max(9, Math.round(PROFILE_SIZE * stampScale));
 151→    const avatarYOffset = Math.max(3, Math.round(6 * stampScale));
 152→    const avatarBottomSpacing = Math.max(6, Math.round(10 * stampScale));
 153→    const avatarLabelSize = Math.max(6, Math.round(8 * stampScale));
 154→    const emojiImage = useEmojiImage(icon, stampSize);
 155→    const stampX = clamp((stamp?.x || 0) * stageWidth, 0, Math.max(0, stageWidth - stampSize));
 156→    const stampY = clamp((stamp?.y || 0) * stageHeight, 0, Math.max(0, stageHeight - (stampSize + profileSize + avatarBottomSpacing)));
 157→    const avatarCenterX = stampX + (stampSize / 2);
 158→    const avatarCenterY = stampY + stampSize + (profileSize / 2) + avatarYOffset;
 159→    const avatarRadius = profileSize / 2;
 160→    const avatarStrokeWidth = Math.max(0.5, 0.7 * stampScale);
 161→
 162→    const handleDelete = () => {
 163→        if(canDelete){
 164→            onDelete();
 165→        }
 166→    };
 167→
 168→    return (
 169→        <Group onClick={handleDelete} onTap={handleDelete}>
 170→            <Circle
 171→                x={stampX + (stampSize / 2)}
 172→                y={stampY + (stampSize / 2)}
 173→                radius={(stampSize / 2) + Math.max(1, 1.8 * stampScale)}
 174→                fill="rgba(255,255,255,0.78)"
 175→                shadowColor="rgba(0,0,0,0.22)"
 176→                shadowBlur={Math.max(3, 5 * stampScale)}
 177→                shadowOffsetY={Math.max(1, 2 * stampScale)}
 178→                listening={false}
 179→            />
 180→            {emojiImage ? (
 181→                <KonvaImage
 182→                    x={stampX}
 183→                    y={stampY}
 184→                    width={stampSize}
 185→                    height={stampSize}
 186→                    image={emojiImage}
 187→                    listening={false}
 188→                />
 189→            ) : (
 190→                <Text
 191→                    x={stampX}
 192→                    y={stampY}
 193→                    width={stampSize}
 194→                    height={stampSize}
 195→                    text={icon}
 196→                    fontSize={stampFontSize}
 197→                    align="center"
 198→                    verticalAlign="middle"
 199→                    listening={false}
 200→                />
 201→            )}
 202→            <Circle
 203→                x={avatarCenterX}
