 219→                        width={profileSize}
 220→                        height={profileSize}
 221→                        image={avatarImage}
 222→                        listening={false}
 223→                    />
 224→                </Group>
 225→            ) : (
 226→                <>
 227→                    <Circle
 228→                        x={avatarCenterX}
 229→                        y={avatarCenterY}
 230→                        radius={avatarRadius}
 231→                        fill="#c9d0dc"
 232→                        stroke="rgba(255,255,255,0.95)"
 233→                        strokeWidth={avatarStrokeWidth}
 234→                        listening={false}
 235→                    />
